34	// Authenticator is the interface for all authentication methods.
35	// Each authenticator determines if it can handle a login request (CanLogin)
36	// and performs the actual authentication (Login).
37	type Authenticator interface {
38		// CanLogin determines if this authenticator can handle the login request.
39		// It returns the user object if available and a boolean indicating if this
40		// authenticator should attempt the login. This method should not perform
41		// expensive operations or actual authentication.
42		CanLogin(user *schema.User, username string, rw http.ResponseWriter, r *http.Request) (*schema.User, bool)
43	
44		// Login performs the actually authentication for the user.
45		// It returns the authenticated user or an error if authentication fails.
46		// The user parameter may be nil if the user doesn't exist in the database yet.
47		Login(user *schema.User, rw http.ResponseWriter, r *http.Request) (*schema.User, error)
48	}
