128	func (auth *Authentication) AuthViaSession(
129		rw http.ResponseWriter,
130		r *http.Request,
131	) (*schema.User, error) {
132		session, err := auth.sessionStore.Get(r, "session")
133		if err != nil {
134			cclog.Error("Error while getting session store")
135			return nil, err
136		}
137	
138		if session.IsNew {
139			return nil, nil
140		}
141	
142		// Validate session data with proper type checking
143		username, ok := session.Values["username"].(string)
144		if !ok || username == "" {
145			cclog.Warn("Invalid session: missing or invalid username")
146			// Invalidate the corrupted session
147			session.Options.MaxAge = -1
148			_ = auth.sessionStore.Save(r, rw, session)
149			return nil, errors.New("invalid session data")
150		}
151	
152		projects, ok := session.Values["projects"].([]string)
153		if !ok {
154			cclog.Warn("Invalid session: projects not found or invalid type, using empty list")
155			projects = []string{}
156		}
157	
158		roles, ok := session.Values["roles"].([]string)
159		if !ok || len(roles) == 0 {
160			cclog.Warn("Invalid session: missing or invalid roles")
161			// Invalidate the corrupted session
162			session.Options.MaxAge = -1
163			_ = auth.sessionStore.Save(r, rw, session)
164			return nil, errors.New("invalid session data")
165		}
166	
167		authSourceInt, ok := session.Values["authSource"].(int)
168		if !ok {
169			authSourceInt = int(schema.AuthViaLocalPassword)
170		}
171	
172		return &schema.User{
173			Username:   username,
174			Projects:   projects,
175			Roles:      roles,
176			AuthType:   schema.AuthSession,
177			AuthSource: schema.AuthSource(authSourceInt),
178		}, nil
179	}
