181	func Init(authCfg *json.RawMessage) {
182		initOnce.Do(func() {
183			authInstance = &Authentication{}
184	
185			// Start background cleanup of rate limiters
186			startRateLimiterCleanup()
187	
188			sessKey := os.Getenv("SESSION_KEY")
189			if sessKey == "" {
190				cclog.Warn("environment variable 'SESSION_KEY' not set (will use non-persistent random key)")
191				bytes := make([]byte, 32)
192				if _, err := rand.Read(bytes); err != nil {
193					cclog.Fatal("Error while initializing authentication -> failed to generate random bytes for session key")
194				}
195				authInstance.sessionStore = sessions.NewCookieStore(bytes)
196			} else {
197				bytes, err := base64.StdEncoding.DecodeString(sessKey)
198				if err != nil {
199					cclog.Fatal("Error while initializing authentication -> decoding session key failed")
200				}
201				authInstance.sessionStore = sessions.NewCookieStore(bytes)
202			}
203	
204			if d, err := time.ParseDuration(config.Keys.SessionMaxAge); err == nil {
205				authInstance.SessionMaxAge = d
206			}
207	
208			if authCfg == nil {
209				return
210			}
211	
212			config.Validate(configSchema, *authCfg)
213			dec := json.NewDecoder(bytes.NewReader(*authCfg))
214			dec.DisallowUnknownFields()
215			if err := dec.Decode(&Keys); err != nil {
216				cclog.Errorf("error while decoding ldap config: %v", err)
217			}
218	
219			if Keys.LdapConfig != nil {
220				ldapAuth := &LdapAuthenticator{}
221				if err := ldapAuth.Init(); err != nil {
222					cclog.Warn("Error while initializing authentication -> ldapAuth init failed")
223				} else {
224					authInstance.LdapAuth = ldapAuth
225					authInstance.authenticators = append(authInstance.authenticators, authInstance.LdapAuth)
226				}
227			} else {
228				cclog.Info("Missing LDAP configuration: No LDAP support!")
229			}
230	
231			if Keys.JwtConfig != nil {
232				authInstance.JwtAuth = &JWTAuthenticator{}
233				if err := authInstance.JwtAuth.Init(); err != nil {
234					cclog.Fatal("Error while initializing authentication -> jwtAuth init failed")
235				}
236	
237				jwtSessionAuth := &JWTSessionAuthenticator{}
238				if err := jwtSessionAuth.Init(); err != nil {
239					cclog.Info("jwtSessionAuth init failed: No JWT login support!")
240				} else {
241					authInstance.authenticators = append(authInstance.authenticators, jwtSessionAuth)
242				}
243	
244				jwtCookieSessionAuth := &JWTCookieSessionAuthenticator{}
245				if err := jwtCookieSessionAuth.Init(); err != nil {
246					cclog.Info("jwtCookieSessionAuth init failed: No JWT cookie login support!")
247				} else {
248					authInstance.authenticators = append(authInstance.authenticators, jwtCookieSessionAuth)
249				}
250			} else {
251				cclog.Info("Missing JWT configuration: No JWT token support!")
252			}
253	
254			authInstance.LocalAuth = &LocalAuthenticator{}
255			if err := authInstance.LocalAuth.Init(); err != nil {
256				cclog.Fatal("Error while initializing authentication -> localAuth init failed")
257			}
258			authInstance.authenticators = append(authInstance.authenticators, authInstance.LocalAuth)
259		})
260	}
