270	// handleUserSync syncs or updates a user in the database based on configuration.
271	// This is used for LDAP, JWT and OIDC authentications when syncUserOnLogin or updateUserOnLogin is enabled.
272	func handleUserSync(user *schema.User, syncUserOnLogin, updateUserOnLogin bool) {
273		r := repository.GetUserRepository()
274		dbUser, err := r.GetUser(user.Username)
275	
276		if err != nil && err != sql.ErrNoRows {
277			cclog.Errorf("Error while loading user '%s': %v", user.Username, err)
278			return
279		}
280	
281		if err == sql.ErrNoRows && syncUserOnLogin { // Add new user
282			if err := r.AddUser(user); err != nil {
283				cclog.Errorf("Error while adding user '%s' to DB: %v", user.Username, err)
284			}
285		} else if err == nil && updateUserOnLogin { // Update existing user
286			if err := r.UpdateUser(dbUser, user); err != nil {
287				cclog.Errorf("Error while updating user '%s' in DB: %v", dbUser.Username, err)
288			}
289		}
290	}
