307	func (auth *Authentication) SaveSession(rw http.ResponseWriter, r *http.Request, user *schema.User) error {
308		session, err := auth.sessionStore.New(r, "session")
309		if err != nil {
310			cclog.Errorf("session creation failed: %s", err.Error())
311			http.Error(rw, err.Error(), http.StatusInternalServerError)
312			return err
313		}
314	
315		if auth.SessionMaxAge != 0 {
316			session.Options.MaxAge = int(auth.SessionMaxAge.Seconds())
317		}
318		if r.TLS == nil && r.Header.Get("X-Forwarded-Proto") != "https" {
319			// If neither TLS or an encrypted reverse proxy are used, do not mark cookies as secure.
320			cclog.Warn("Authenticating with unencrypted request. Session cookies will not have Secure flag set (insecure for production)")
321			if r.Header.Get("X-Forwarded-Proto") == "" {
322				// This warning will not be printed if e.g. X-Forwarded-Proto == http
323				cclog.Warn("If you are using a reverse proxy, make sure X-Forwarded-Proto is set")
324			}
325			session.Options.Secure = false
326		}
327		session.Options.SameSite = http.SameSiteLaxMode
328		session.Values["username"] = user.Username
329		session.Values["projects"] = user.Projects
330		session.Values["roles"] = user.Roles
331		session.Values["authSource"] = int(user.AuthSource)
332		if err := auth.sessionStore.Save(r, rw, session); err != nil {
333			cclog.Warnf("session save failed: %s", err.Error())
334			http.Error(rw, err.Error(), http.StatusInternalServerError)
335			return err
336		}
337	
338		return nil
339	}
