341	func (auth *Authentication) Login(
342		onfailure func(rw http.ResponseWriter, r *http.Request, loginErr error),
343	) http.Handler {
344		return http.HandlerFunc(func(rw http.ResponseWriter, r *http.Request) {
345			ip, _, err := net.SplitHostPort(r.RemoteAddr)
346			if err != nil {
347				ip = r.RemoteAddr
348			}
349	
350			username := r.FormValue("username")
351	
352			limiter := getIPUserLimiter(ip, username)
353			if !limiter.Allow() {
354				cclog.Warnf("AUTH/RATE > Too many login attempts for combination IP: %s, Username: %s", ip, username)
355				onfailure(rw, r, errors.New("too many login attempts, try again in a few minutes"))
356				return
357			}
358	
359			var dbUser *schema.User
360			if username != "" {
361				var err error
362				dbUser, err = repository.GetUserRepository().GetUser(username)
363				if err != nil && err != sql.ErrNoRows {
364					cclog.Errorf("Error while loading user '%v'", username)
365				}
366			}
367	
368			for _, authenticator := range auth.authenticators {
369				var ok bool
370				var user *schema.User
371				if user, ok = authenticator.CanLogin(dbUser, username, rw, r); !ok {
372					continue
373				} else {
374					cclog.Debugf("Can login with user %v", user)
375				}
376	
377				user, err := authenticator.Login(user, rw, r)
378				if err != nil {
379					cclog.Warnf("user login failed: %s", err.Error())
380					onfailure(rw, r, err)
381					return
382				}
383	
384				if err := auth.SaveSession(rw, r, user); err != nil {
385					return
386				}
387	
388				cclog.Infof("login successfull: user: %#v (roles: %v, projects: %v)", user.Username, user.Roles, user.Projects)
389				ctx := context.WithValue(r.Context(), repository.ContextUserKey, user)
390	
391				if r.FormValue("redirect") != "" {
392					http.RedirectHandler(r.FormValue("redirect"), http.StatusFound).ServeHTTP(rw, r.WithContext(ctx))
393					return
394				}
395	
396				http.RedirectHandler("/", http.StatusFound).ServeHTTP(rw, r.WithContext(ctx))
397				return
398			}
399	
400			cclog.Debugf("login failed: no authenticator applied")
401			onfailure(rw, r, errors.New("no authenticator applied"))
402		})
403	}
