405	func (auth *Authentication) Auth(
406		onsuccess http.Handler,
407		onfailure func(rw http.ResponseWriter, r *http.Request, authErr error),
408	) http.Handler {
409		return http.HandlerFunc(func(rw http.ResponseWriter, r *http.Request) {
410			user, err := auth.JwtAuth.AuthViaJWT(rw, r)
411			if err != nil {
412				cclog.Infof("auth -> authentication failed: %s", err.Error())
413				http.Error(rw, err.Error(), http.StatusUnauthorized)
414				return
415			}
416			if user == nil {
417				user, err = auth.AuthViaSession(rw, r)
418				if err != nil {
419					cclog.Infof("auth -> authentication failed: %s", err.Error())
420					http.Error(rw, err.Error(), http.StatusUnauthorized)
421					return
422				}
423			}
424			if user != nil {
425				ctx := context.WithValue(r.Context(), repository.ContextUserKey, user)
426				onsuccess.ServeHTTP(rw, r.WithContext(ctx))
427				return
428			}
429	
430			cclog.Infof("auth -> authentication failed: no valid session or JWT for %s %s from %s", r.Method, r.URL.Path, r.RemoteAddr)
431			onfailure(rw, r, errors.New("unauthorized (please login first)"))
432		})
433	}
