435	func (auth *Authentication) AuthAPI(
436		onsuccess http.Handler,
437		onfailure func(rw http.ResponseWriter, r *http.Request, authErr error),
438	) http.Handler {
439		return http.HandlerFunc(func(rw http.ResponseWriter, r *http.Request) {
440			user, err := auth.JwtAuth.AuthViaJWT(rw, r)
441			if err != nil {
442				cclog.Infof("auth api -> authentication failed: %s", err.Error())
443				onfailure(rw, r, err)
444				return
445			}
446	
447			ipErr := securedCheck(user, r)
448			if ipErr != nil {
449				cclog.Infof("auth api -> secured check failed: %s", ipErr.Error())
450				onfailure(rw, r, ipErr)
451				return
452			}
453	
454			if user != nil {
455				switch {
456				case len(user.Roles) == 1:
457					if user.HasRole(schema.RoleAPI) {
458						ctx := context.WithValue(r.Context(), repository.ContextUserKey, user)
459						onsuccess.ServeHTTP(rw, r.WithContext(ctx))
460						return
461					}
462				case len(user.Roles) >= 2:
463					if user.HasAllRoles([]schema.Role{schema.RoleAdmin, schema.RoleAPI}) {
464						ctx := context.WithValue(r.Context(), repository.ContextUserKey, user)
465						onsuccess.ServeHTTP(rw, r.WithContext(ctx))
466						return
467					}
468				default:
469					cclog.Info("auth api -> authentication failed: missing role")
470					onfailure(rw, r, errors.New("unauthorized"))
471				}
472			}
473			cclog.Info("auth api -> authentication failed: no auth")
474			onfailure(rw, r, errors.New("unauthorized"))
475		})
476	}
