595			if err != nil {
596				http.Error(rw, err.Error(), http.StatusInternalServerError)
597				return
598			}
599	
600			if !session.IsNew {
601				session.Options.MaxAge = -1
602				if err := auth.sessionStore.Save(r, rw, session); err != nil {
603					http.Error(rw, err.Error(), http.StatusInternalServerError)
604					return
605				}
606			}
607	
608			onsuccess.ServeHTTP(rw, r)
609		})
610	}
611	
612	// Helper Moved To MiddleWare Auth Handlers
613	func securedCheck(user *schema.User, r *http.Request) error {
614		if user == nil {
615			return fmt.Errorf("no user for secured check")
616		}
617	
618		// extract IP address for checking
619		IPAddress := r.Header.Get("X-Real-Ip")
620		if IPAddress == "" {
621			IPAddress = r.Header.Get("X-Forwarded-For")
622		}
623		if IPAddress == "" {
624			IPAddress = r.RemoteAddr
625		}
626	
627		// Handle both IPv4 and IPv6 addresses properly
628		// For IPv6, this will strip the port and brackets
629		// For IPv4, this will strip the port
630		if host, _, err := net.SplitHostPort(IPAddress); err == nil {
631			IPAddress = host
632		}
633		// If SplitHostPort fails, IPAddress is already just a host (no port)
634	
635		// If nothing declared in config: Continue
636		if len(config.Keys.APIAllowedIPs) == 0 {
637			return nil
638		}
639		// If wildcard declared in config: Continue
640		if config.Keys.APIAllowedIPs[0] == "*" {
641			return nil
642		}
643		// check if IP is allowed
644		if !util.Contains(config.Keys.APIAllowedIPs, IPAddress) {
645			return fmt.Errorf("unknown ip: %v", IPAddress)
646		}
647	
648		return nil
649	}
650

