22		"github.com/ClusterCockpit/cc-backend/pkg/metricstore"
23		cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
24		lp "github.com/ClusterCockpit/cc-lib/v2/ccMessage"
25		"github.com/ClusterCockpit/cc-lib/v2/nats"
26		"github.com/ClusterCockpit/cc-lib/v2/receivers"
27		"github.com/ClusterCockpit/cc-lib/v2/schema"
28		influx "github.com/ClusterCockpit/cc-line-protocol/v2/lineprotocol"
29	)
30	
31	// natsMessage wraps a raw NATS message with its subject for channel-based processing.
32	type natsMessage struct {
33		subject string
34		data    []byte
35	}
36	
37	// NatsAPI provides NATS subscription-based handlers for Job and Node operations.
38	// It mirrors the functionality of the REST API but uses NATS messaging with
39	// InfluxDB line protocol as the message format.
40	//
41	// # Message Format
42	//
43	// All NATS messages use InfluxDB line protocol format (https://docs.influxdata.com/influxdb/v2.0/reference/syntax/line-protocol/)
44	// with the following structure:
45	//
46	//	measurement,tag1=value1,tag2=value2 field1=value1,field2=value2 timestamp
47	//
48	// # Job Events
49	//
50	// Job start/stop events use the "job" measurement with a "function" tag to distinguish operations:
51	//
52	//	job,function=start_job event="{...JSON payload...}" <timestamp>
53	//	job,function=stop_job event="{...JSON payload...}" <timestamp>
54	//
55	// The JSON payload in the "event" field follows the schema.Job or StopJobAPIRequest structure.
56	//
57	// Example job start message:
58	//
59	//	job,function=start_job event="{\"jobId\":1001,\"user\":\"testuser\",\"cluster\":\"testcluster\",...}" 1234567890000000000
60	//
61	// # Node State Events
62	//
63	// Node state updates use the "nodestate" measurement with cluster information:
64	//
65	//	nodestate event="{...JSON payload...}" <timestamp>
66	//
67	// The JSON payload follows the UpdateNodeStatesRequest structure.
68	//
69	// Example node state message:
70	//
71	//	nodestate event="{\"cluster\":\"testcluster\",\"nodes\":[{\"hostname\":\"node01\",\"states\":[\"idle\"]}]}" 1234567890000000000
72	type NatsAPI struct {
73		JobRepository *repository.JobRepository
74		// RepositoryMutex protects job creation operations from race conditions
75		// when checking for duplicate jobs during startJob calls.
76		RepositoryMutex sync.Mutex
77		// jobCh receives job event messages for processing by worker goroutines.
78		jobCh chan natsMessage
79		// nodeCh receives node state messages for processing by worker goroutines.
80		nodeCh chan natsMessage
81	}
82	
83	// NewNatsAPI creates a new NatsAPI instance with channel-based worker pools.
84	// Concurrency is configured via NATSConfig (defaults: JobConcurrency=8, NodeConcurrency=2).
85	func NewNatsAPI() *NatsAPI {
86		jobConc := 8
87		nodeConc := 2
88	
89		if s := config.Keys.APISubjects; s != nil {
90			if s.JobConcurrency > 0 {
91				jobConc = s.JobConcurrency
92			}
93			if s.NodeConcurrency > 0 {
94				nodeConc = s.NodeConcurrency
95			}
96		}
97	
98		api := &NatsAPI{
99			JobRepository: repository.GetJobRepository(),
100			jobCh:         make(chan natsMessage, jobConc),
101			nodeCh:        make(chan natsMessage, nodeConc),
102		}
103	
104		// Start worker goroutines
105		for range jobConc {
106			go api.jobWorker()
107		}
108		for range nodeConc {
109			go api.nodeWorker()
110		}
111	
112		return api
113	}
114	
115	// jobWorker processes job event messages from the job channel.
116	func (api *NatsAPI) jobWorker() {
117		for msg := range api.jobCh {
118			api.handleJobEvent(msg.subject, msg.data)
119		}
120	}
121	
122	// nodeWorker processes node state messages from the node channel.
123	func (api *NatsAPI) nodeWorker() {
124		for msg := range api.nodeCh {
125			api.handleNodeState(msg.subject, msg.data)
126		}
127	}
128	
129	// StartSubscriptions registers all NATS subscriptions for Job and Node APIs.
130	// Messages are delivered to buffered channels and processed by worker goroutines.
131	// Returns an error if the NATS client is not available or subscription fails.
132	func (api *NatsAPI) StartSubscriptions() error {
133		client := nats.GetClient()
134		if client == nil {
135			cclog.Warn("NATS client not available, skipping API subscriptions")
136			return nil
137		}
138	
139		if config.Keys.APISubjects != nil {
140			s := config.Keys.APISubjects
141	
142			if err := client.Subscribe(s.SubjectJobEvent, func(subject string, data []byte) {
143				api.jobCh <- natsMessage{subject: subject, data: data}
144			}); err != nil {
145				return err
146			}
147	
148			if err := client.Subscribe(s.SubjectNodeState, func(subject string, data []byte) {
149				api.nodeCh <- natsMessage{subject: subject, data: data}
150			}); err != nil {
151				return err
152			}
153	
154			cclog.Info("NATS API subscriptions started")
155		}
156		return nil
157	}
158	
159	// processJobEvent routes job event messages to the appropriate handler based on the "function" tag.
160	// Validates that required tags and fields are present before processing.
161	func (api *NatsAPI) processJobEvent(msg lp.CCMessage) {
162		function, ok := msg.GetTag("function")
163		if !ok {
164			cclog.Errorf("Job event is missing required tag 'function': measurement=%s", msg.Name())
165			return
166		}
167	
168		switch function {
169		case "start_job":
170			v, ok := msg.GetEventValue()
171			if !ok {
172				cclog.Errorf("Job start event is missing event field with JSON payload")
173				return
174			}
175			api.handleStartJob(v)
176	
177		case "stop_job":
178			v, ok := msg.GetEventValue()
179			if !ok {
180				cclog.Errorf("Job stop event is missing event field with JSON payload")
181				return
182			}
183			api.handleStopJob(v)
184	
185		default:
186			cclog.Warnf("Unknown job event function '%s', expected 'start_job' or 'stop_job'", function)
187		}
188	}
189	
190	// handleJobEvent processes job-related messages received via NATS using InfluxDB line protocol.
191	// The message must be in line protocol format with measurement="job" and include:
192	//   - tag "function" with value "start_job" or "stop_job"
193	//   - field "event" containing JSON payload (schema.Job or StopJobAPIRequest)
194	//
195	// Example: job,function=start_job event="{\"jobId\":1001,...}" 1234567890000000000
196	func (api *NatsAPI) handleJobEvent(subject string, data []byte) {
197		if len(data) == 0 {
198			cclog.Warnf("NATS %s: received empty message", subject)
199			return
200		}
201	
202		d := influx.NewDecoderWithBytes(data)
203	
204		for d.Next() {
205			m, err := receivers.DecodeInfluxMessage(d)
206			if err != nil {
207				cclog.Errorf("NATS %s: failed to decode InfluxDB line protocol message: %v", subject, err)
208				return
209			}
210	
211			if !m.IsEvent() {
212				cclog.Debugf("NATS %s: received non-event message, skipping", subject)
213				continue
214			}
215	
216			if m.Name() == "job" {
217				api.processJobEvent(m)
218			} else {
219				cclog.Debugf("NATS %s: unexpected measurement name '%s', expected 'job'", subject, m.Name())
220			}
221		}
222	}
223	
224	// handleStartJob processes job start messages received via NATS.
225	// The payload parameter contains JSON following the schema.Job structure.
226	// Jobs are validated, checked for duplicates, and inserted into the database.
227	func (api *NatsAPI) handleStartJob(payload string) {
228		if payload == "" {
229			cclog.Error("NATS start job: payload is empty")
230			return
231		}
232		req := schema.Job{
233			Shared:           "none",
234			MonitoringStatus: schema.MonitoringStatusRunningOrArchiving,
235		}
236	
237		dec := json.NewDecoder(strings.NewReader(payload))
238		dec.DisallowUnknownFields()
239		if err := dec.Decode(&req); err != nil {
240			cclog.Errorf("NATS start job: parsing request failed: %v", err)
241			return
242		}
243	
244		cclog.Debugf("NATS start job: %s", req.GoString())
245		req.State = schema.JobStateRunning
246	
247		if err := importer.SanityChecks(&req); err != nil {
248			cclog.Errorf("NATS start job: sanity check failed: %v", err)
249			return
250		}
251	
252		var unlockOnce sync.Once
253		api.RepositoryMutex.Lock()
254		defer unlockOnce.Do(api.RepositoryMutex.Unlock)
255	
256		jobs, err := api.JobRepository.FindAll(&req.JobID, &req.Cluster, nil)
257		if err != nil && err != sql.ErrNoRows {
258			cclog.Errorf("NATS start job: checking for duplicate failed: %v", err)
259			return
260		}
261		if err == nil {
262			for _, job := range jobs {
263				if (req.StartTime - job.StartTime) < secondsPerDay {
264					cclog.Errorf("NATS start job: job with jobId %d, cluster %s already exists (dbid: %d)",
265						req.JobID, req.Cluster, job.ID)
266					return
267				}
268			}
269		}
270	
271		// When tags are present, insert directly into the job table so that the
272		// returned ID can be used with AddTagOrCreate (which queries the job table).
273		var id int64
274		if len(req.Tags) > 0 {
275			id, err = api.JobRepository.StartDirect(&req)
276		} else {
277			id, err = api.JobRepository.Start(&req)
278		}
279		if err != nil {
280			cclog.Errorf("NATS start job: insert into database failed: %v", err)
281			return
282		}
283		unlockOnce.Do(api.RepositoryMutex.Unlock)
284	
285		for _, tag := range req.Tags {
286			if _, err := api.JobRepository.AddTagOrCreate(nil, id, tag.Type, tag.Name, tag.Scope); err != nil {
287				cclog.Errorf("NATS start job: adding tag to new job %d failed: %v", id, err)
288				return
289			}
290		}
291	
292		cclog.Infof("NATS: new job (id: %d): cluster=%s, jobId=%d, user=%s, startTime=%d",
293			id, req.Cluster, req.JobID, req.User, req.StartTime)
294	}
295	
296	// handleStopJob processes job stop messages received via NATS.
297	// The payload parameter contains JSON following the StopJobAPIRequest structure.
298	// The job is marked as stopped in the database and archiving is triggered if monitoring is enabled.
299	func (api *NatsAPI) handleStopJob(payload string) {
300		if payload == "" {
301			cclog.Error("NATS stop job: payload is empty")
302			return
303		}
304		var req StopJobAPIRequest
305	
306		dec := json.NewDecoder(strings.NewReader(payload))
307		dec.DisallowUnknownFields()
308		if err := dec.Decode(&req); err != nil {
309			cclog.Errorf("NATS job stop: parsing request failed: %v", err)
310			return
311		}
312	
313		if req.JobID == nil {
314			cclog.Errorf("NATS job stop: the field 'jobId' is required")
315			return
316		}
317	
318		isCached := false
319		job, err := api.JobRepository.FindCached(req.JobID, req.Cluster, req.StartTime)
320		if err != nil {
321			// Not in cache, try main job table
322			job, err = api.JobRepository.Find(req.JobID, req.Cluster, req.StartTime)
323			if err != nil {
324				cclog.Errorf("NATS job stop: finding job failed: %v", err)
325				return
326			}
327		} else {
328			isCached = true
329		}
330	
331		if job.State != schema.JobStateRunning {
332			cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: job has already been stopped (state is: %s)",
333				job.JobID, job.ID, job.Cluster, job.State)
334			return
335		}
336	
337		if job.StartTime > req.StopTime {
338			cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: stopTime %d must be >= startTime %d",
339				job.JobID, job.ID, job.Cluster, req.StopTime, job.StartTime)
340			return
341		}
342	
343		if req.State != "" && !req.State.Valid() {
344			cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: invalid job state: %#v",
345				job.JobID, job.ID, job.Cluster, req.State)
346			return
347		} else if req.State == "" {
348			req.State = schema.JobStateCompleted
349		}
350	
351		job.Duration = int32(req.StopTime - job.StartTime)
352		job.State = req.State
353		api.JobRepository.Mutex.Lock()
354		defer api.JobRepository.Mutex.Unlock()
355	
356		// If the job is still in job_cache, transfer it to the job table first
357		if isCached {
358			newID, err := api.JobRepository.TransferCachedJobToMain(*job.ID)
359			if err != nil {
360				cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: transferring cached job failed: %v",
361					job.JobID, *job.ID, job.Cluster, err)
362				return
363			}
364			cclog.Infof("NATS: transferred cached job to main table: old id %d -> new id %d (jobId=%d)", *job.ID, newID, job.JobID)
365			job.ID = &newID
366		}
367	
368		if err := api.JobRepository.Stop(*job.ID, job.Duration, job.State, job.MonitoringStatus); err != nil {
369			cclog.Errorf("NATS job stop: jobId %d (id %d) on %s: marking job as '%s' failed: %v",
370				job.JobID, *job.ID, job.Cluster, job.State, err)
371			return
372		}
373	
374		cclog.Infof("NATS: archiving job (dbid: %d): cluster=%s, jobId=%d, user=%s, startTime=%d, duration=%d, state=%s",
375			*job.ID, job.Cluster, job.JobID, job.User, job.StartTime, job.Duration, job.State)
376	
377		if job.MonitoringStatus == schema.MonitoringStatusDisabled {
378			return
379		}
380	
381		archiver.TriggerArchiving(job)
382	}
383	
384	// processNodestateEvent extracts and processes node state data from the InfluxDB message.
385	// Updates node states in the repository for all nodes in the payload.
386	func (api *NatsAPI) processNodestateEvent(msg lp.CCMessage) {
387		v, ok := msg.GetEventValue()
388		if !ok {
389			cclog.Errorf("Nodestate event is missing event field with JSON payload")
390			return
391		}
392	
393		var req UpdateNodeStatesRequest
394	
395		dec := json.NewDecoder(strings.NewReader(v))
396		dec.DisallowUnknownFields()
397		if err := dec.Decode(&req); err != nil {
398			cclog.Errorf("NATS nodestate: parsing request failed: %v", err)
399			return
400		}
401	
402		repo := repository.GetNodeRepository()
403		requestReceived := time.Now().Unix()
404	
405		// Pre-compute node states; only include non-down nodes in health check
406		nodeStates := make(map[string]schema.SchedulerState, len(req.Nodes))
407		for _, node := range req.Nodes {
408			nodeStates[node.Hostname] = determineState(node.States)
409		}
410	
411		// Build nodeList per subcluster for health check, skipping down nodes
412		m := make(map[string][]string)
413		metricNames := make(map[string][]string)
414		healthResults := make(map[string]metricstore.HealthCheckResult)
415	
416		for _, node := range req.Nodes {
417			if nodeStates[node.Hostname] == schema.NodeStateDown {
418				continue
419			}
420			if sc, err := archive.GetSubClusterByNode(req.Cluster, node.Hostname); err == nil {
421				m[sc] = append(m[sc], node.Hostname)
422			}
423		}
424	
425		for sc := range m {
426			if sc != "" {
427				metricList := archive.GetMetricConfigSubCluster(req.Cluster, sc)
428				metricNames[sc] = metricListToNames(metricList)
429			}
430		}
431	
432		// Perform health check against metric store
433		healthRepo, err := metricdispatch.GetHealthCheckRepo(req.Cluster)
434		if err != nil {
435			cclog.Warnf("NATS nodestate: no metric store for cluster %s, skipping health check: %v", req.Cluster, err)
436		} else {
437			for sc, nl := range m {
438				if sc != "" {
439					if results, err := healthRepo.HealthCheck(req.Cluster, nl, metricNames[sc]); err == nil {
440						maps.Copy(healthResults, results)
441					}
442				}
443			}
444		}
445	
446		updates := make([]repository.NodeStateUpdate, 0, len(req.Nodes))
447		for _, node := range req.Nodes {
448			state := nodeStates[node.Hostname]
449			var healthState schema.MonitoringState
450			var healthMetrics string
451			if state == schema.NodeStateDown {
452				healthState = schema.MonitoringStateFull
453			} else {
454				healthState = schema.MonitoringStateFailed
455				if result, ok := healthResults[node.Hostname]; ok {
456					healthState = result.State
457					healthMetrics = result.HealthMetrics
458				}
459			}
460			nodeState := schema.NodeStateDB{
461				TimeStamp:       requestReceived,
462				NodeState:       state,
463				CpusAllocated:   node.CpusAllocated,
464				MemoryAllocated: node.MemoryAllocated,
465				GpusAllocated:   node.GpusAllocated,
466				HealthState:     healthState,
467				HealthMetrics:   healthMetrics,
468				JobsRunning:     node.JobsRunning,
469			}
470			updates = append(updates, repository.NodeStateUpdate{
471				Hostname:  node.Hostname,
472				Cluster:   req.Cluster,
473				NodeState: &nodeState,
474			})
475		}
476	
477		if err := repo.BatchUpdateNodeStates(updates); err != nil {
478			cclog.Errorf("NATS nodestate: batch update for cluster %s failed: %v", req.Cluster, err)
479		}
480	
481		cclog.Debugf("NATS nodestate: updated %d node states for cluster %s", len(req.Nodes), req.Cluster)
482	}
483	
484	// handleNodeState processes node state update messages received via NATS using InfluxDB line protocol.
485	// The message must be in line protocol format with measurement="nodestate" and include:
486	//   - field "event" containing JSON payload (UpdateNodeStatesRequest)
487	//
488	// Example: nodestate event="{\"cluster\":\"testcluster\",\"nodes\":[...]}" 1234567890000000000
489	func (api *NatsAPI) handleNodeState(subject string, data []byte) {
490		if len(data) == 0 {
491			cclog.Warnf("NATS %s: received empty message", subject)
492			return
493		}
494	
495		d := influx.NewDecoderWithBytes(data)
496	
497		for d.Next() {
498			m, err := receivers.DecodeInfluxMessage(d)
499			if err != nil {
500				cclog.Errorf("NATS %s: failed to decode InfluxDB line protocol message: %v", subject, err)
501				return
502			}
503	
504			if !m.IsEvent() {
505				cclog.Warnf("NATS %s: received non-event message, skipping", subject)
506				continue
507			}
508	
509			if m.Name() == "nodestate" {
510				api.processNodestateEvent(m)
511			} else {
512				cclog.Warnf("NATS %s: unexpected measurement name '%s', expected 'nodestate'", subject, m.Name())
513			}
514		}
515	}
